1	package codex
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"slices"
7		"strings"
8	
9		"github.com/johnnyfreeman/viewscreen/config"
10		"github.com/johnnyfreeman/viewscreen/render"
11		"github.com/johnnyfreeman/viewscreen/style"
12		"github.com/johnnyfreeman/viewscreen/terminal"
13		"github.com/johnnyfreeman/viewscreen/textutil"
14	)
15	
16	// maxOutputLines caps how many lines of command output are shown when not
17	// running verbosely, mirroring the truncation the Claude renderers apply.
18	const maxOutputLines = 25
19	
20	// argWidth is the maximum width of a header argument (command/path) before it
21	// is truncated. Matches the tools header renderer.
22	const argWidth = 80
23	
24	// Renderer turns codex events into styled terminal output. It is stateful: a
25	// single Renderer instance must be used for the lifetime of one stream so that
26	// it can deduplicate items that codex reports more than once (an item.started
27	// followed by an item.completed for the same id).
28	type Renderer struct {
29		md         *render.MarkdownRenderer
30		config     config.Provider
31		headerSeen map[string]bool
32	}
33	
34	// RendererOption configures a Renderer.
35	type RendererOption func(*Renderer)
36	
37	// WithConfigProvider sets a custom config provider.
38	func WithConfigProvider(cp config.Provider) RendererOption {
39		return func(r *Renderer) {
40			r.config = cp
41		}
42	}
43	
44	// WithMarkdownRenderer sets a custom markdown renderer (used in tests).
45	func WithMarkdownRenderer(md *render.MarkdownRenderer) RendererOption {
46		return func(r *Renderer) {
47			r.md = md
48		}
49	}
50	
51	// NewRenderer creates a Renderer with default dependencies.
52	func NewRenderer(opts ...RendererOption) *Renderer {
53		cfg := config.Get()
54		r := &Renderer{
55			config:     cfg,
56			md:         render.NewMarkdownRenderer(cfg.NoColor(), terminal.Width()),
57			headerSeen: make(map[string]bool),
58		}
59		for _, opt := range opts {
60			opt(r)
61		}
62		return r
63	}
64	
65	// SetWidth updates the word-wrap width of the markdown renderer.
66	func (r *Renderer) SetWidth(width int) {
67		r.md.SetWidth(width)
68	}
69	
70	// Render renders a single codex event to a string. It returns "" for events
71	// that produce no output (e.g. turn.started, or a duplicate item).
72	func (r *Renderer) Render(event Event) string {
73		switch event.Type {
74		case TypeThreadStarted:
75			return r.renderThreadStarted(event)
76		case TypeTurnCompleted:
77			return r.renderTurnCompleted(event)
78		case TypeTurnFailed:
79			return r.renderTurnFailed(event)
80		case TypeError:
81			return r.renderError(event.Message)
82		case TypeItemStarted:
83			return r.renderItem("started", event.Item)
84		case TypeItemUpdated:
85			return r.renderItem("updated", event.Item)
86		case TypeItemCompleted:
87			return r.renderItem("completed", event.Item)
88		default: // turn.started and any unknown envelope
89			return ""
90		}
91	}
92	
93	// once reports whether id is being seen for the first time, marking it seen.
94	func (r *Renderer) once(id string) bool {
95		if id == "" {
96			return true // unidentified items always render
97		}
98		if r.headerSeen[id] {
99			return false
100		}
101		r.headerSeen[id] = true
102		return true
103	}
104	
105	func (r *Renderer) renderThreadStarted(event Event) string {
106		out := render.StringOutput()
107		fmt.Fprintln(out, style.BulletHeader("Codex Session"))
108		if event.ThreadID != "" {
109			fmt.Fprintf(out, "%s%s %s\n", style.OutputPrefix, style.MutedText("Thread:"), event.ThreadID)
110		}
111		fmt.Fprintln(out)
112		return out.String()
113	}
114	
115	func (r *Renderer) renderTurnCompleted(event Event) string {
116		out := render.StringOutput()
117		fmt.Fprintln(out)
118		fmt.Fprintln(out, style.BulletSuccessHeader("Turn Complete"))
119		if event.Usage != nil && r.config.ShowUsage() {
120			u := event.Usage
121			fmt.Fprintf(out, "%s%s in=%d out=%d (cached=%d reasoning=%d)\n",
122				style.OutputPrefix, style.MutedText("Tokens:"),
123				u.InputTokens, u.OutputTokens, u.CachedInputTokens, u.ReasoningOutputTokens)
124		}
125		return out.String()
126	}
127	
128	func (r *Renderer) renderTurnFailed(event Event) string {
129		msg := ""
130		if event.Error != nil {
131			msg = event.Error.Message
132		}
133		out := render.StringOutput()
134		fmt.Fprintln(out)
135		fmt.Fprintln(out, style.BulletErrorHeader("Turn Failed"))
136		if msg != "" {
137			fmt.Fprintf(out, "%s%s\n", style.OutputPrefix, style.ErrorText(msg))
138		}
139		return out.String()
140	}
141	
142	func (r *Renderer) renderError(message string) string {
143		out := render.StringOutput()
144		fmt.Fprintln(out, style.BulletErrorHeader("Error"))
145		if message != "" {
146			fmt.Fprintf(out, "%s%s\n", style.OutputPrefix, style.ErrorText(message))
147		}
148		return out.String()
149	}
150	
151	func (r *Renderer) renderItem(phase string, item *Item) string {
152		if item == nil {
153			return ""
154		}
155		switch item.Type {
156		case ItemAgentMessage:
157			if item.Text == "" || !r.once(item.ID) {
158				return ""
159			}
160			return r.md.Render(item.Text)
161		case ItemReasoning:
162			if item.Text == "" || !r.once(item.ID) {
163				return ""
164			}
165			return r.renderReasoning(item.Text)
166		case ItemCommandExecution:
167			return r.renderCommand(phase, item)
168		case ItemFileChange:
169			if !r.once(item.ID) {
170				return ""
171			}
172			return r.renderFileChange(item)
173		case ItemTodoList:
174			if !r.once(item.ID) {
175				return ""
176			}
177			return r.renderTodoList(item)
178		case ItemMCPToolCall:
179			return r.renderMCPToolCall(phase, item)
180		case ItemWebSearch:
181			if !r.once(item.ID) {
182				return ""
183			}
184			return r.renderWebSearch(item)
185		case ItemError:
186			if !r.once(item.ID) {
187				return ""
188			}
189			return r.renderError(firstNonEmpty(item.Message, item.Text))
190		default:
191			return r.renderUnknownItem(phase, item)
192		}
193	}
194	
195	func (r *Renderer) renderReasoning(text string) string {
196		out := render.StringOutput()
197		fmt.Fprintln(out, style.MutedText(style.Bullet+" Thinking"))
198		fmt.Fprint(out, r.md.RenderMuted(text))
199		return out.String()
200	}
201	
202	// renderCommand renders a shell command. The header (the command itself) is
203	// printed the first time the item is seen; the output and exit status are
204	// printed when the item completes.
205	func (r *Renderer) renderCommand(phase string, item *Item) string {
206		out := render.StringOutput()
207		if r.once(item.ID) {
208			fmt.Fprint(out, header("Shell", ShellCommand(item.Command)))
209		}
210		if phase == "completed" {
211			r.writeCommandOutput(out, item)
212		}
213		return out.String()
214	}
215	
216	func (r *Renderer) writeCommandOutput(out *render.Output, item *Item) {
217		pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
218		body := strings.TrimRight(item.AggregatedOutput, "\n")
219		if body != "" {
220			for _, line := range r.capLines(strings.Split(body, "\n")) {
221				pw.WriteLine(line)
222			}
223		}
224		if item.ExitCode != nil && *item.ExitCode != 0 {
225			pw.WriteLine(style.ErrorText(fmt.Sprintf("exited with code %d", *item.ExitCode)))
226		} else if item.Status == "failed" {
227			pw.WriteLine(style.ErrorText("failed"))
228		} else if body == "" {
229			pw.WriteLine(style.MutedText("(no output)"))
230		}
231	}
232	
233	func (r *Renderer) renderFileChange(item *Item) string {
234		out := render.StringOutput()
235		fmt.Fprint(out, header("Edit", FileChangeSummary(item.Changes)))
236		if len(item.Changes) > 1 {
237			pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
238			for _, c := range item.Changes {
239				pw.WriteLinef("%s %s", changeKindLabel(c.Kind), c.Path)
240			}
241		}
242		return out.String()
243	}
244	
245	func (r *Renderer) renderTodoList(item *Item) string {
246		out := render.StringOutput()
247		fmt.Fprint(out, header("Update Todos", ""))
248		pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
249		for _, todo := range item.Items {
250			if todo.Completed {
251				pw.WriteLinef("%s %s", style.SuccessText("✓"), style.MutedText(todo.Text))
252			} else {
253				pw.WriteLinef("%s %s", style.MutedText("○"), todo.Text)
254			}
255		}
256		return out.String()
257	}
258	
259	func (r *Renderer) renderMCPToolCall(phase string, item *Item) string {
260		out := render.StringOutput()
261		if r.once(item.ID) {
262			fmt.Fprint(out, header(MCPLabel(item), ""))
263		}
264		if phase == "completed" && item.Status == "failed" {
265			pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
266			pw.WriteLine(style.ErrorText("failed"))
267		}
268		return out.String()
269	}
270	
271	func (r *Renderer) renderWebSearch(item *Item) string {
272		return header("Web Search", item.Query)
273	}
274	
275	func (r *Renderer) renderUnknownItem(phase string, item *Item) string {
276		out := render.StringOutput()
277		arg := firstNonEmpty(item.Command, item.Query, item.Status)
278		if r.once(item.ID) {
279			fmt.Fprint(out, header(unknownItemLabel(item.Type), arg))
280		}
281		if phase == "completed" || phase == "updated" {
282			r.writeUnknownItemDetails(out, item, arg)
283		}
284		return out.String()
285	}
286	
287	func (r *Renderer) writeUnknownItemDetails(out *render.Output, item *Item, headerArg string) {
288		pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
289		detail := firstNonEmpty(item.Message, item.Text)
290		if detail != "" && detail != headerArg {
291			for _, line := range strings.Split(strings.TrimRight(detail, "\n"), "\n") {
292				pw.WriteLine(line)
293			}
294		}
295		if item.Status == "failed" {
296			pw.WriteLine(style.ErrorText("failed"))
297		}
298		if r.config.IsVerbose() && len(item.Raw) > 0 {
299			if compact := compactRawItem(item.Raw); compact != "" {
300				pw.WriteLine(style.MutedText(compact))
301			}
302		}
303	}
304	
305	// capLines truncates a slice of output lines unless verbose output is enabled.
306	func (r *Renderer) capLines(lines []string) []string {
307		if r.config.IsVerbose() || len(lines) <= maxOutputLines {
308			return lines
309		}
310		hidden := len(lines) - maxOutputLines
311		kept := slices.Clone(lines[:maxOutputLines])
312		return append(kept, style.MutedText(fmt.Sprintf("… (+%d more lines)", hidden)))
313	}
314	
315	// header renders a tool-style header line: a gradient bullet + label, followed
316	// by an optional muted argument. It mirrors the layout of tools.HeaderRenderer
317	// so codex output is visually consistent with the Claude renderers.
318	func header(label, arg string) string {
319		var b strings.Builder
320		b.WriteString(style.ApplyThemeBoldGradient(style.Bullet + " " + label))
321		if arg != "" {
322			b.WriteString(" " + style.MutedText(truncate(arg, argWidth)))
323		}
324		b.WriteString("\n")
325		return b.String()
326	}
327	
328	// ShellCommand extracts the inner command from codex's shell invocation,
329	// which wraps commands as "<shell> -lc <script>". It is exported so callers
330	// that need the human-readable command (e.g. the live spinner label) share the
331	// same unwrapping the renderer uses for command headers.
332	func ShellCommand(cmd string) string {
333		for _, sep := range []string{" -lc ", " -c "} {
334			if i := strings.Index(cmd, sep); i != -1 {
335				return unquote(strings.TrimSpace(cmd[i+len(sep):]))
336			}
337		}
338		return cmd
339	}
340	
341	func unquote(s string) string {
342		if len(s) >= 2 {
343			first, last := s[0], s[len(s)-1]
344			if (first == '\'' && last == '\'') || (first == '"' && last == '"') {
345				return s[1 : len(s)-1]
346			}
347		}
348		return s
349	}
350	
351	// FileChangeSummary returns the human-readable argument for a file_change item:
352	// the single path when only one file is touched, or "N files" otherwise. It is
353	// exported so the live spinner can label an in-flight file change the same way
354	// the inline header does (mirroring ShellCommand and MCPLabel).
355	func FileChangeSummary(changes []FileChange) string {
356		switch len(changes) {
357		case 0:
358			return ""
359		case 1:
360			return changes[0].Path
361		default:
362			return fmt.Sprintf("%d files", len(changes))
363		}
364	}
365	
366	func changeKindLabel(kind string) string {
367		switch kind {
368		case "add":
369			return style.SuccessText("add")
370		case "delete":
371			return style.ErrorText("delete")
372		default:
373			return style.WarningText("update")
374		}
375	}
376	
377	// MCPLabel returns a "server.tool" label for an mcp_tool_call item, falling
378	// back to whichever of server/tool is present. It is exported so the live
379	// spinner can label an in-flight MCP call the same way the header does.
380	func MCPLabel(item *Item) string {
381		switch {
382		case item.Server != "" && item.Tool != "":
383			return item.Server + "." + item.Tool
384		case item.Tool != "":
385			return item.Tool
386		case item.Server != "":
387			return item.Server
388		default:
389			return "MCP Tool"
390		}
391	}
392	
393	func unknownItemLabel(itemType string) string {
394		if itemType == "" {
395			return "Codex Item"
396		}
397		parts := strings.Fields(strings.NewReplacer("_", " ", "-", " ").Replace(itemType))
398		for i, part := range parts {
399			parts[i] = strings.ToUpper(part[:1]) + part[1:]
400		}
401		return strings.Join(parts, " ")
402	}
403	
404	func compactRawItem(raw json.RawMessage) string {
405		var v any
406		if err := json.Unmarshal(raw, &v); err != nil {
407			return ""
408		}
409		b, err := json.Marshal(v)
410		if err != nil {
411			return ""
412		}
413		return string(b)
414	}
415	
416	func truncate(s string, max int) string {
417		s = strings.ReplaceAll(s, "\n", " ")
418		if len(s) > max {
419			return s[:max-3] + "..."
420		}
421		return s
422	}
423	
424	func firstNonEmpty(values ...string) string {
425		for _, v := range values {
426			if v != "" {
427				return v
428			}
429		}
430		return ""
431	}
432

