1	package events
2	
3	import (
4		"strings"
5	
6		"github.com/johnnyfreeman/viewscreen/assistant"
7		"github.com/johnnyfreeman/viewscreen/codex"
8		"github.com/johnnyfreeman/viewscreen/config"
9		"github.com/johnnyfreeman/viewscreen/result"
10		"github.com/johnnyfreeman/viewscreen/state"
11		"github.com/johnnyfreeman/viewscreen/stream"
12		"github.com/johnnyfreeman/viewscreen/style"
13		"github.com/johnnyfreeman/viewscreen/system"
14		"github.com/johnnyfreeman/viewscreen/tools"
15		"github.com/johnnyfreeman/viewscreen/user"
16	)
17	
18	// ProcessResult contains the output from processing an event.
19	type ProcessResult struct {
20		// Rendered is the rendered content to append to output
21		Rendered string
22		// HasPendingTools indicates whether there are pending tools waiting for results
23		HasPendingTools bool
24	}
25	
26	// EventProcessor processes parsed events, updates state, and produces rendered output.
27	// It separates the event processing logic from the TUI concerns.
28	type EventProcessor struct {
29		renderers *RendererSet
30		state     *state.State
31	
32		codexActiveTools map[string]codexActiveTool
33		codexToolOrder   []string
34	}
35	
36	type codexActiveTool struct {
37		name  string
38		input string
39	}
40	
41	// NewEventProcessor creates a new EventProcessor with the given state.
42	func NewEventProcessor(s *state.State) *EventProcessor {
43		return &EventProcessor{
44			renderers:        NewRendererSet(),
45			state:            s,
46			codexActiveTools: make(map[string]codexActiveTool),
47		}
48	}
49	
50	// NewEventProcessorWithRenderers creates a new EventProcessor with custom renderers.
51	// This allows reusing an existing RendererSet, useful for testing or when
52	// renderers need specific configuration.
53	func NewEventProcessorWithRenderers(s *state.State, rs *RendererSet) *EventProcessor {
54		return &EventProcessor{
55			renderers:        rs,
56			state:            s,
57			codexActiveTools: make(map[string]codexActiveTool),
58		}
59	}
60	
61	// Renderers returns the underlying RendererSet for direct access when needed.
62	func (p *EventProcessor) Renderers() *RendererSet {
63		return p.renderers
64	}
65	
66	// SetWidth updates the word-wrap width for all markdown renderers.
67	// This is called when the viewport resizes.
68	func (p *EventProcessor) SetWidth(width int) {
69		p.renderers.SetWidth(width)
70	}
71	
72	// Process handles a parsed event and returns the rendered result.
73	func (p *EventProcessor) Process(event Event) ProcessResult {
74		p.detectAgent(event)
75		switch e := event.(type) {
76		case SystemEvent:
77			return p.processSystem(e.Data)
78		case SubAgentSystemEvent:
79			return ProcessResult{}
80		case AssistantEvent:
81			return p.processAssistant(e.Data)
82		case UserEvent:
83			return p.processUser(e.Data)
84		case StreamEvent:
85			return p.processStream(e.Data)
86		case ResultEvent:
87			return p.processResult(e.Data)
88		case CodexEvent:
89			return p.processCodex(e.Data)
90		case IgnoredEvent:
91			return ProcessResult{}
92		default:
93			return ProcessResult{}
94		}
95	}
96	
97	// detectAgent records which CLI produced the stream so the TUI can brand
98	// itself accordingly. Codex envelope events are unambiguous; every other
99	// concrete event type comes from Claude Code's stream-json. Ignored or empty
100	// events leave the current value untouched so a seeded agent (prompt mode)
101	// survives until a definitive event arrives.
102	func (p *EventProcessor) detectAgent(event Event) {
103		switch event.(type) {
104		case CodexEvent:
105			p.state.Agent = config.AgentCodex
106		case SystemEvent, SubAgentSystemEvent, AssistantEvent, UserEvent, StreamEvent, ResultEvent:
107			p.state.Agent = config.AgentClaude
108		}
109	}
110	
111	// HasPendingTools returns whether there are pending tools awaiting results.
112	func (p *EventProcessor) HasPendingTools() bool {
113		return p.renderers.PendingTools.Len() > 0
114	}
115	
116	// RenderPendingTool renders a pending tool with the given icon (for spinner animation).
117	func (p *EventProcessor) RenderPendingTool(pending tools.PendingTool, icon string) string {
118		opts := []tools.HeaderRendererOption{tools.WithIcon(icon)}
119		if p.renderers.PendingTools.IsNested(pending) {
120			opts = append(opts, tools.WithNested())
121		}
122		r := tools.NewHeaderRenderer(opts...)
123		str, _ := r.RenderBlockToString(pending.Block)
124		return str
125	}
126	
127	// ForEachPendingTool iterates over all pending tools.
128	func (p *EventProcessor) ForEachPendingTool(fn func(id string, pending tools.PendingTool)) {
129		p.renderers.PendingTools.ForEach(fn)
130	}
131	
132	func (p *EventProcessor) processSystem(event system.Event) ProcessResult {
133		// Claude transcript logs include many non-init system metadata events
134		// (e.g. turn_duration, local_command). Ignore these to avoid rendering
135		// repeated empty "Session Started" blocks.
136		if event.Subtype != "" && event.Subtype != "init" {
137			return ProcessResult{}
138		}
139	
140		p.state.UpdateFromSystemEvent(event)
141	
142		// Skip rendering for system events with no meaningful data.
143		// These are typically subagent events that lack parent_tool_use_id.
144		if event.Model == "" && event.CWD == "" && len(event.Tools) == 0 {
145			return ProcessResult{}
146		}
147	
148		rendered := p.renderers.System.RenderToString(event)
149		return ProcessResult{Rendered: rendered}
150	}
151	
152	func (p *EventProcessor) processAssistant(event assistant.Event) ProcessResult {
153		p.state.IncrementTurnCount()
154	
155		// Accumulate per-turn token usage for real-time tracking
156		if u := event.Message.Usage; u != nil {
157			p.state.AccumulateUsage(u.InputTokens, u.OutputTokens, u.CacheCreationInputTokens, u.CacheReadInputTokens)
158		}
159	
160		r := p.renderers
161	
162		// Buffer tool_use blocks using the tracker's method
163		msg := tools.AssistantMessage{
164			Content:         event.Message.Content,
165			ParentToolUseID: event.ParentToolUseID,
166		}
167		if r.PendingTools.BufferFromAssistantMessage(msg, r.Stream.InToolUseBlock()) {
168			// Update state to show the first pending tool
169			for _, block := range event.Message.Content {
170				if block.Type == "tool_use" && block.ID != "" {
171					p.state.SetCurrentTool(block.Name, tools.GetToolArgFromBlock(block))
172					break
173				}
174			}
175		}
176	
177		// Render text blocks only (tools are buffered)
178		rendered := r.Assistant.RenderToString(
179			event,
180			r.Stream.InTextBlock(),
181			true, // Suppress tool rendering - we handle it separately
182		)
183		r.Stream.ResetBlockState()
184	
185		return ProcessResult{
186			Rendered:        rendered,
187			HasPendingTools: r.PendingTools.Len() > 0,
188		}
189	}
190	
191	func (p *EventProcessor) processUser(event user.Event) ProcessResult {
192		p.state.UpdateFromToolUseResult(event.ToolUseResult)
193		r := p.renderers
194	
195		var content strings.Builder
196		var isNested bool
197	
198		// Check if this is a sub-agent prompt (text content with parent_tool_use_id)
199		if event.ParentToolUseID != nil && p.isSubAgentPrompt(event) {
200			// Resolve the parent tool early and render its header
201			if resolved := r.PendingTools.ResolveParentEarly(*event.ParentToolUseID); resolved != nil {
202				isNested = resolved.IsNested
203				str, _ := tools.RenderResolved(*resolved)
204				content.WriteString(str)
205			}
206			// Render the prompt text with truncation
207			if isNested {
208				content.WriteString(r.User.RenderNestedSubAgentPromptToString(event))
209			} else {
210				content.WriteString(r.User.RenderSubAgentPromptToString(event))
211			}
212			return ProcessResult{
213				Rendered:        content.String(),
214				HasPendingTools: r.PendingTools.Len() > 0,
215			}
216		}
217	
218		// Match tool results with pending tools using the tracker's method
219		msg := tools.UserMessage{
220			Content: make([]tools.UserToolResult, len(event.Message.Content)),
221		}
222		for i, c := range event.Message.Content {
223			msg.Content[i] = tools.UserToolResult{
224				Type:      c.Type,
225				ToolUseID: c.ToolUseID,
226			}
227		}
228		matched := r.PendingTools.MatchFromUserMessage(msg)
229	
230		// Render matched tool headers (unless already rendered) and set context
231		for _, match := range matched {
232			isNested = match.IsNested
233			if !match.HeaderRendered {
234				str, ctx := tools.RenderResolved(match.ResolvedTool)
235				content.WriteString(str)
236				r.User.SetToolContext(ctx)
237			} else {
238				// Header was rendered early, just set context
239				_, ctx := tools.RenderResolved(match.ResolvedTool)
240				r.User.SetToolContext(ctx)
241			}
242		}
243	
244		// Clear tool state if no more pending tools
245		if r.PendingTools.Len() == 0 {
246			p.state.ClearCurrentTool()
247		}
248	
249		// Render the tool result (with nested prefix if applicable)
250		if isNested {
251			content.WriteString(r.User.RenderNestedToString(event))
252		} else {
253			content.WriteString(r.User.RenderToString(event))
254		}
255	
256		return ProcessResult{
257			Rendered:        content.String(),
258			HasPendingTools: r.PendingTools.Len() > 0,
259		}
260	}
261	
262	// isSubAgentPrompt checks if a user event is a sub-agent prompt.
263	// Sub-agent prompts have text content (not tool_result) and are used to pass
264	// the prompt to a Task sub-agent.
265	func (p *EventProcessor) isSubAgentPrompt(event user.Event) bool {
266		for _, c := range event.Message.Content {
267			if c.Type == "text" {
268				return true
269			}
270		}
271		return false
272	}
273	
274	func (p *EventProcessor) processStream(event stream.Event) ProcessResult {
275		r := p.renderers
276		rendered := r.Stream.RenderToString(event)
277	
278		// Update state for tool progress tracking
279		if event.Event.Type == "content_block_start" && r.Stream.InToolUseBlock() {
280			toolName := r.Stream.CurrentToolName()
281			if toolName == "" {
282				toolName = r.Stream.CurrentBlockType()
283			}
284			p.state.SetCurrentTool(toolName, "")
285		}
286	
287		return ProcessResult{Rendered: rendered}
288	}
289	
290	func (p *EventProcessor) processResult(event result.Event) ProcessResult {
291		r := p.renderers
292	
293		var content strings.Builder
294	
295		// Flush any orphaned pending tools using the tracker's method
296		orphaned := r.PendingTools.FlushAll()
297		for _, o := range orphaned {
298			str, _ := tools.RenderResolved(o.ResolvedTool)
299			content.WriteString(str)
300			content.WriteString(style.OutputPrefix + style.MutedText("(no result)") + "\n")
301		}
302	
303		p.state.ClearCurrentTool()
304		p.state.UpdateFromResultEvent(event)
305		content.WriteString(r.Result.RenderToString(event))
306	
307		return ProcessResult{Rendered: content.String()}
308	}
309	
310	// processCodex handles an event from the Codex CLI stream. Codex events are
311	// rendered by a dedicated codex.Renderer; this method also folds the event's
312	// effect into the shared state (token usage, the live "Running" spinner, and
313	// the sidebar task list) so the TUI reflects a codex stream the same way it
314	// reflects a Claude one.
315	func (p *EventProcessor) processCodex(event codex.Event) ProcessResult {
316		p.applyCodexState(event)
317		return ProcessResult{Rendered: p.renderers.Codex.Render(event)}
318	}
319	
320	// applyCodexState updates the shared TUI state from a codex event. Codex runs
321	// one item at a time, so an item.started for a long-running item (a shell
322	// command, MCP call, file change, or web search) sets the current tool for the
323	// spinner, and the matching item.completed — or the end of the turn — clears it.
324	// turn.started bumps the turn counter so the sidebar reflects work in progress
325	// the way it does for Claude (whose assistant messages drive the count).
326	func (p *EventProcessor) applyCodexState(event codex.Event) {
327		switch event.Type {
328		case codex.TypeTurnStarted:
329			p.state.IncrementTurnCount()
330		case codex.TypeTurnCompleted:
331			if event.Usage != nil {
332				u := event.Usage
333				p.state.AccumulateUsage(u.InputTokens, u.OutputTokens, 0, u.CachedInputTokens)
334				p.state.ReasoningTokens += u.ReasoningOutputTokens
335			}
336			p.clearCodexActiveTools()
337		case codex.TypeTurnFailed:
338			p.clearCodexActiveTools()
339		case codex.TypeItemStarted, codex.TypeItemUpdated, codex.TypeItemCompleted:
340			p.applyCodexItem(event.Type, event.Item)
341		}
342	}
343	
344	// applyCodexItem applies a single codex work item to the spinner and task list.
345	// The spinner label matches the item's inline header so the live view and the
346	// scrollback agree on what codex is doing.
347	func (p *EventProcessor) applyCodexItem(phase string, item *codex.Item) {
348		if item == nil {
349			return
350		}
351		completed := phase == codex.TypeItemCompleted
352		switch item.Type {
353		case codex.ItemTodoList:
354			// Replace the sidebar task list on every update so it tracks the
355			// latest completion state, even though the inline render dedupes by id.
356			p.state.Todos = codexTodos(item.Items)
357		case codex.ItemCommandExecution:
358			p.updateCodexActiveTool(completed, item.ID, "Shell", codex.ShellCommand(item.Command))
359		case codex.ItemMCPToolCall:
360			p.updateCodexActiveTool(completed, item.ID, codex.MCPLabel(item), "")
361		case codex.ItemFileChange:
362			p.updateCodexActiveTool(completed, item.ID, "Edit", codex.FileChangeSummary(item.Changes))
363		case codex.ItemWebSearch:
364			p.updateCodexActiveTool(completed, item.ID, "Web Search", item.Query)
365		}
366	}
367	
368	// updateCodexActiveTool shows the newest in-flight codex tool in the live
369	// spinner while preserving older overlapping items. Codex can start multiple
370	// command_execution items before completing them; when the visible item
371	// completes, the spinner falls back to the next still-active item instead of
372	// going blank.
373	func (p *EventProcessor) updateCodexActiveTool(completed bool, id, name, input string) {
374		if id == "" {
375			if completed {
376				p.state.ClearCurrentTool()
377			} else {
378				p.state.SetCurrentTool(name, input)
379			}
380			return
381		}
382	
383		if completed {
384			delete(p.codexActiveTools, id)
385			p.removeCodexToolOrder(id)
386			p.restoreLatestCodexTool()
387			return
388		}
389	
390		if p.codexActiveTools == nil {
391			p.codexActiveTools = make(map[string]codexActiveTool)
392		}
393		if _, exists := p.codexActiveTools[id]; !exists {
394			p.codexToolOrder = append(p.codexToolOrder, id)
395		}
396		p.codexActiveTools[id] = codexActiveTool{name: name, input: input}
397		p.state.SetCurrentTool(name, input)
398	}
399	
400	func (p *EventProcessor) restoreLatestCodexTool() {
401		for i := len(p.codexToolOrder) - 1; i >= 0; i-- {
402			id := p.codexToolOrder[i]
403			if tool, ok := p.codexActiveTools[id]; ok {
404				p.state.SetCurrentTool(tool.name, tool.input)
405				return
406			}
407		}
408		p.state.ClearCurrentTool()
409	}
410	
411	func (p *EventProcessor) clearCodexActiveTools() {
412		clear(p.codexActiveTools)
413		p.codexToolOrder = nil
414		p.state.ClearCurrentTool()
415	}
416	
417	func (p *EventProcessor) removeCodexToolOrder(id string) {
418		for i, activeID := range p.codexToolOrder {
419			if activeID == id {
420				p.codexToolOrder = append(p.codexToolOrder[:i], p.codexToolOrder[i+1:]...)
421				return
422			}
423		}
424	}
425	
426	// codexTodos maps codex todo_list items onto the shared todo model. Codex only
427	// reports a boolean completion (no explicit in-progress marker), so each item is
428	// either completed or pending.
429	func codexTodos(items []codex.TodoItem) []state.Todo {
430		todos := make([]state.Todo, len(items))
431		for i, it := range items {
432			status := "pending"
433			if it.Completed {
434				status = "completed"
435			}
436			todos[i] = state.Todo{Content: it.Text, Status: status}
437		}
438		return todos
439	}
440

