2	
3	import (
4		"bufio"
5		"os"
6		"path/filepath"
7		"strings"
8		"testing"
9	
10		"github.com/johnnyfreeman/viewscreen/state"
11	)
12	
13	// TestProcessAllTestdata verifies that every .jsonl file in testdata/ can be
14	// parsed and processed through the full EventProcessor pipeline without errors.
15	// This catches regressions when the Claude Code output format evolves.
16	func TestProcessAllTestdata(t *testing.T) {
17		testdataDir := filepath.Join("..", "testdata")
18		entries, err := os.ReadDir(testdataDir)
19		if err != nil {
20			t.Fatalf("failed to read testdata directory: %v", err)
21		}
22	
23		var jsonlFiles []string
24		for _, entry := range entries {
25			if !entry.IsDir() && strings.HasSuffix(entry.Name(), ".jsonl") {
26				jsonlFiles = append(jsonlFiles, entry.Name())
27			}
28		}
29	
30		if len(jsonlFiles) == 0 {
31			t.Fatal("no .jsonl files found in testdata/")
32		}
33	
34		for _, filename := range jsonlFiles {
35			t.Run(filename, func(t *testing.T) {
36				filePath := filepath.Join(testdataDir, filename)
37				f, err := os.Open(filePath)
38				if err != nil {
39					t.Fatalf("failed to open %s: %v", filename, err)
40				}
41				defer f.Close()
42	
43				s := state.NewState()
44				processor := NewEventProcessor(s)
45	
46				scanner := bufio.NewScanner(f)
47				const maxCapacity = 10 * 1024 * 1024
48				buf := make([]byte, maxCapacity)
49				scanner.Buffer(buf, maxCapacity)
50	
51				lineNum := 0
52				var parseErrors []string
53				var eventCounts = make(map[string]int)
54	
55				for scanner.Scan() {
56					lineNum++
57					line := scanner.Text()
58					if line == "" {
59						continue
60					}
61	
62					parsed := Parse(line)
63					if parsed == nil {
64						continue
65					}
66	
67					switch e := parsed.(type) {
68					case ParseError:
69						if e.Err != nil {
70							parseErrors = append(parseErrors, e.Err.Error())
71						} else if !strings.HasPrefix(e.Line, "Unknown event type:") {
72							parseErrors = append(parseErrors, e.Line)
73						}
74						// Unknown event types are logged but not fatal
75						continue
76					case SystemEvent:
77						eventCounts["system"]++
78					case SubAgentSystemEvent:
79						eventCounts["subagent_system"]++
80					case AssistantEvent:
81						eventCounts["assistant"]++
82					case UserEvent:
83						eventCounts["user"]++
84					case StreamEvent:
85						eventCounts["stream"]++
86					case ResultEvent:
87						eventCounts["result"]++
88					case CodexEvent:
89						eventCounts["codex"]++
90					case IgnoredEvent:
91						eventCounts["ignored"]++
92						continue
93					}
94	
95					// Process through EventProcessor - should not panic
96					processor.Process(parsed)
97				}
98	
